var adminReadmeTmpl = `# Admin scaffold

This folder contains generated admin UI scaffolding (controllers, views, routes).

To mount the admin routes in your application main, call the generated mount function in your main.go. For example:

    // inside main
    MountAdminPostsRoutes(app)

Replace or implement TODOs in the generated controller actions to add persistence and validation.

Internationalization (i18n)

This project includes a minimal i18n scaffold under ` + "app/i18n" + ` with an example ` + "en.yaml" + `. To enable translations at runtime:

    import (
        "github.com/your/module/path/pkg/i18n" // replace with your module path
        flow "github.com/undiegomejia/flow/pkg/flow"
    )

    // during app init
    mgr := i18n.NewManager()
    _ = mgr.LoadDir("app/i18n")
    app.Use(i18n.Middleware(mgr, "en"))

In handlers, use the helper ` + "i18n.TFromContext" + ` to fetch translated strings from the request context. Example:

    func (c *PostsAdminController) Index(ctx *flow.Context) {
        title := i18n.TFromContext(ctx.R.Context(), "admin.posts.index")
        _ = c.Render(ctx, "admin/posts/index", map[string]interface{}{"Title": title})
    }
`

var authControllerTmpl = `// Code generated by flow generate auth; DO NOT EDIT.
package controllers

import (
    "net/http"
    "context"
    "fmt"
    flow "github.com/undiegomejia/flow/pkg/flow"
    "golang.org/x/crypto/bcrypt"
    // NOTE: the generated controller imports your app's models package.
    // Replace the placeholder import path below with your module path when
    // generating into a standalone project. Tests will patch this placeholder
    // during compile checks.
    models "REPLACE_WITH_MODULE_PATH/app/models"
)

// AuthController provides simple login/logout handlers backed by sessions.
type AuthController struct{ *flow.Controller }

func NewAuthController(app *flow.App) *AuthController {
    return &AuthController{Controller: flow.NewController(app)}
}

// Login renders the login page (GET) and handles authentication (POST).
func (c *AuthController) Login(ctx *flow.Context) {
    if ctx.R.Method == http.MethodGet {
        _ = ctx.Render("auth/login", map[string]interface{}{"Title": "Login"})
        return
    }
    // POST: authenticate
    email := ctx.FormValue("email")
    pass := ctx.FormValue("password")

    // require Bun to be configured for DB-backed auth
    if ctx.App == nil || ctx.App.Bun() == nil {
        _ = ctx.AddFlash("error", "server not configured for DB-backed auth")
        ctx.Redirect("/login", 302)
        return
    }

    // lookup user using the generated typed models.User
    var u models.User
    err := ctx.App.Bun().NewSelect().Model(&u).Where("email = ?", email).Scan(context.Background())
    if err != nil {
        _ = ctx.AddFlash("error", "invalid credentials")
        _ = ctx.Render("auth/login", map[string]interface{}{"Title": "Login", "Email": email})
        return
    }
    if bcrypt.CompareHashAndPassword([]byte(u.Password_hash), []byte(pass)) != nil {
        _ = ctx.AddFlash("error", "invalid credentials")
        _ = ctx.Render("auth/login", map[string]interface{}{"Title": "Login", "Email": email})
        return
    }

    // success: set session (store user_id as string to avoid JSON numeric decoding issues)
    sess := ctx.Session()
    if sess != nil {
        _ = sess.Set("user_id", fmt.Sprintf("%d", u.ID))
        _ = sess.Set("user_role", u.Role)
    }
    ctx.Redirect("/", 302)
}

func (c *AuthController) Logout(ctx *flow.Context) {
    s := ctx.Session()
    if s != nil {
        _ = s.Delete("user_id")
        _ = s.Delete("user_role")
    }
    ctx.Redirect("/", 302)
}
`

