var authMiddlewareTmpl = `// Code generated by flow generate auth middleware; DO NOT EDIT.
package middleware

import (
    "context"
    "net/http"
    "strconv"
    flow "github.com/undiegomejia/flow/pkg/flow"
    // NOTE: the generated middleware imports your app's models package so it
    // can attach a typed *models.User to the request context. When generating
    // into a standalone project replace the placeholder below with your module
    // path. Tests will patch this placeholder during compile checks.
    models "REPLACE_WITH_MODULE_PATH/app/models"
)

// GetSessionUserID converts the session-stored user_id (string) into an int64.
func GetSessionUserID(s *flow.Session) (int64, bool) {
    if s == nil {
        return 0, false
    }
    v, ok := s.Get("user_id")
    if !ok {
        return 0, false
    }
    vs, ok := v.(string)
    if !ok {
        return 0, false
    }
    id, err := strconv.ParseInt(vs, 10, 64)
    if err != nil {
        return 0, false
    }
    return id, true
}

// GetCurrentUser returns the typed *models.User attached to the request by the
// generated middleware, if any.
func GetCurrentUser(r *http.Request) (*models.User, bool) {
    if v := r.Context().Value(userCtxKey{}); v != nil {
        if u, ok := v.(*models.User); ok {
            return u, true
        }
    }
    return nil, false
}

type userCtxKey struct{}

// RequireLogin redirects unauthenticated requests to /login. It relies on
// session keys set by the login controller (user_id). It will attach a
// typed *models.User to the request context constructed from session data.
func RequireLogin() flow.Middleware {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            s := flow.FromContext(r.Context())
            if s == nil {
                http.Redirect(w, r, "/login", http.StatusFound)
                return
            }

            id, ok := GetSessionUserID(s)
            if !ok || id == 0 {
                http.Redirect(w, r, "/login", http.StatusFound)
                return
            }

            // construct a minimal models.User from session data. This avoids
            // requiring a DB lookup in middleware; controllers that need full
            // user data can still fetch from DB using ctx.App.
            var role string
            if rv, ok := s.Get("user_role"); ok {
                if rs, ok2 := rv.(string); ok2 {
                    role = rs
                }
            }
            mu := &models.User{Model: flow.Model{ID: id}, Role: role}

            ctx := context.WithValue(r.Context(), userCtxKey{}, mu)
            next.ServeHTTP(w, r.WithContext(ctx))
        })
    }
}

// RequireRole returns middleware that ensures the session's user_role
// matches the provided role. It first checks the session and denies if not present.
func RequireRole(role string) flow.Middleware {
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            s := flow.FromContext(r.Context())
            if s == nil {
                http.Error(w, "forbidden", http.StatusForbidden)
                return
            }
            if v, ok := s.Get("user_role"); ok {
                if rv, ok2 := v.(string); ok2 && rv == role {
                    next.ServeHTTP(w, r)
                    return
                }
            }
            http.Error(w, "forbidden", http.StatusForbidden)
        })
    }
}
`

var authReadmeTmpl = `# Auth scaffold

This folder contains generated auth scaffolding: a login/logout controller,
login view, and middleware helpers. The generator also creates a User model and migrations.

Mount the middleware in your main application to protect routes. Example:

    // in main.go
    import "app/middleware"
    app.Use(middleware.RequireLogin())

Creating an initial user (example):

    package main

    import (
        "context"
        "log"
        "golang.org/x/crypto/bcrypt"

    flow "github.com/undiegomejia/flow/pkg/flow"
    orm "github.com/undiegomejia/flow/internal/orm"
        models "github.com/your/module/path/app/models" // replace with your module path
    )

    func main() {
        ctx := context.Background()
        adapter, err := orm.Connect("file::memory:?cache=shared")
        if err != nil {
            log.Fatal(err)
        }
        defer adapter.Close()

        app := flow.New("init-user", flow.WithBun(adapter))
        pw, _ := bcrypt.GenerateFromPassword([]byte("secret123"), bcrypt.DefaultCost)
    u := &models.User{Email: "admin@example.com", Password_hash: string(pw), Role: "admin"}
        if err := u.Save(ctx, app); err != nil {
            log.Fatal(err)
        }
    }

The generated auth controller uses bcrypt for password verification and Bun
for DB lookups. Ensure your App is configured with Bun (app.SetBun(...)) before using the login handlers.

Using GetCurrentUser in handlers

The generated middleware attaches a typed *models.User into the request
context. You can access it from handlers using the exported helper
GetCurrentUser. Replace the module path imports below with your module
path if needed.

    // inside a controller handler
    import (
        middleware "github.com/your/module/path/app/middleware" // replace
        models "github.com/your/module/path/app/models"        // replace
        flow "github.com/undiegomejia/flow/pkg/flow"
    )

    func (c *DashboardController) Index(ctx *flow.Context) {
        if u, ok := middleware.GetCurrentUser(ctx.R); ok {
            // u is *models.User — you can inspect fields such as u.Email or u.Role
            ctx.Render("dashboard/index", map[string]interface{}{"User": u}, ctx)
            return
        }
        // not authenticated — redirect to login
        ctx.Redirect("/login", 302)
    }

Using GetSessionUserID in handlers

The generated middleware stores user_id as a string in the session. Use the
exported GetSessionUserID helper to parse it safely when you need the numeric
ID in your handlers. Example:

    import (
        middleware "github.com/your/module/path/app/middleware" // replace
        flow "github.com/undiegomejia/flow/pkg/flow"
    )

    func (c *SomeController) Show(ctx *flow.Context) {
        if s := ctx.Session(); s != nil {
            if id, ok := middleware.GetSessionUserID(s); ok {
                // id is the authenticated user's ID (int64)
                _ = id // use it, e.g. fetch full user from DB via app.Bun()
            }
        }
        // ...handler logic
    }

Internationalization (i18n)

A minimal i18n scaffold is created under ` + "app/i18n" + ` (example ` + "en.yaml" + `).
Enable it by creating a Manager, loading the i18n directory and registering the middleware:

    import (
        "github.com/your/module/path/pkg/i18n" // replace with your module path
        flow "github.com/undiegomejia/flow/pkg/flow"
    )

    mgr := i18n.NewManager()
    _ = mgr.LoadDir("app/i18n")
    app.Use(i18n.Middleware(mgr, "en"))

In controllers, fetch translations with ` + "i18n.TFromContext" + `:

    func (c *DashboardController) Index(ctx *flow.Context) {
        title := i18n.TFromContext(ctx.R.Context(), "auth.login")
        _ = c.Render(ctx, "dashboard/index", map[string]interface{}{"Title": title}, ctx)
    }
`

